import { Box, Container, Spacer, VStack ,Checkbox, Input } from "@chakra-ui/react"
import { useState } from "react"

export const IncompleteTodos = (props) => {
    const { incompleteTodos, onClickComplete, onClickDelete } = props;

    const [editing, setEditing] = useState();

    const handleSubmit = (index) => {
      // インプットに表示された内容を保存
      setEditing(false);
    }

    const handleEditing = (index) => {
      // 未完了タスクをコピー
      // const newIncompleteTodos = [...incompleteTodos]
      // 編集対象のタスクを取得
      // console.log(newIncompleteTodos);
      // タスクを編集するためのインプットを表示 
    }

    return (
    <div>
            <VStack>
            <Container maxW='xl' bg='blue.600' color='white'>
        <p>未完了のToDo</p>
        <ul>
          {incompleteTodos.map((todo, index) => (
          <li key={todo}>
            <Box display="flex" p={2}>
            <Checkbox onChange={() => onClickComplete(index)}></Checkbox>
            <p>{todo}</p>
            <Spacer />
            <Box px={2}>



            <form>
          {editing ? (
            <div>
              <input type="text"/>
              <button onClick={handleSubmit}>Save</button>
            </div>
          ) : (
            <div>
              <button onClick={() => handleEditing(index)}>Edit</button>
            </div>
          )}
        </form>


            </Box>
            <button onClick={() => onClickDelete(index)}>削除</button>

            </Box>
          </li>
            )
        )}
        </ul>
        </Container>
        </VStack>
    </div>
    )
}
